#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/time.h>

#define ARRAY_SIZE 10000000 // 10 million elements
#define MAX_THREADS 64

// Get current time in seconds
double get_time_seconds() {
 struct timeval tv;
 gettimeofday(&tv, NULL);
 return tv.tv_sec + tv.tv_usec / 1000000.0;
}

// Sequential reduction (baseline)
double sequential_sum(double *arr, int n) {
 double sum = 0.0;
 for (int i = 0; i < n; i++) {
 sum += arr[i];
 }
 return sum;
}

// Parallel reduction using OpenMP
// This demonstrates strong scaling with a fixed problem size
double parallel_sum_omp(double *arr, int n, int num_threads) {
 double sum = 0.0;

 #pragma omp parallel for reduction(+:sum) num_threads(num_threads)
 for (int i = 0; i < n; i++) {
 sum += arr[i];
 }
 return sum;
}

// Simulate parallel reduction with artificial overhead
// Mimics MIMD system with communication overhead
typedef struct {
 double local_sum;
 int start_idx;
 int end_idx;
} PartialResult;

// Simulated parallel reduction (for educational demonstration)
// Models communication overhead and synchronization
double simulated_parallel_sum(double *arr, int n, int num_threads) {
 if (num_threads == 1) {
 return sequential_sum(arr, n);
 }

 int chunk_size = n / num_threads;
 double total_sum = 0.0;

 // Simulate parallel computation with overhead
 for (int t = 0; t < num_threads; t++) {
 int start = t * chunk_size;
 int end = (t == num_threads - 1) ? n : start + chunk_size;

 // Local reduction (computation)
 double local_sum = 0.0;
 for (int i = start; i < end; i++) {
 local_sum += arr[i];
 }

 // Simulate communication overhead (increases with threads)
 // This models the overhead in real MIMD systems
 double overhead_factor = 1.0 + (0.001 * num_threads); // 0.1% per thread
 total_sum += local_sum * overhead_factor;
 }

 return total_sum;
}

// Calculate speedup: S(p) = T(1) / T(p)
double calculate_speedup(double t_sequential, double t_parallel) {
 return t_sequential / t_parallel;
}

// Calculate efficiency: E(p) = S(p) / p
double calculate_efficiency(double speedup, int num_threads) {
 return speedup / num_threads;
}

// Apply Amdahl's Law: S(p) <= 1 / (f + (1-f)/p)
double amdahls_law(double sequential_fraction, int num_processors) {
 double f = sequential_fraction;
 double p = num_processors;
 return 1.0 / (f + (1.0 - f) / p);
}

void print_scaling_analysis(double *times, int max_threads) {
 double t_1 = times[1];

 printf("\n=========================================================\n");
 printf("STRONG SCALING ANALYSIS (Fixed Problem Size: %d elements)\n", ARRAY_SIZE);
 printf("=========================================================\n");
 printf("%-10s %-12s %-12s %-12s %-12s %-12s\n", 
 "Threads", "Time(s)", "Speedup", "Efficiency", "Amdahl(5%)", "Amdahl(10%)");
 printf("---------------------------------------------------------\n");

 for (int p = 1; p <= max_threads; p++) {
 double speedup = calculate_speedup(t_1, times[p]);
 double efficiency = calculate_efficiency(speedup, p);
 double amdahl_5 = amdahls_law(0.05, p);
 double amdahl_10 = amdahls_law(0.10, p);

 printf("%-10d %-12.4f %-12.2f %-12.2f%% %-12.2f %-12.2f\n", 
 p, times[p], speedup, efficiency * 100, amdahl_5, amdahl_10);
 }

 printf("\nKEY OBSERVATIONS:\n");
 printf("- Ideal linear speedup would be %dx with 100%% efficiency\n", max_threads);
 printf("- Actual speedup with %d threads: %.2fx (efficiency: %.2f%%)\n", 
 max_threads, calculate_speedup(t_1, times[max_threads]),
 calculate_efficiency(calculate_speedup(t_1, times[max_threads]), max_threads) * 100);
 printf("- Theoretical max (Amdahl f=5%%): %.2fx\n", amdahls_law(0.05, max_threads));
 printf("- Theoretical max (Amdahl f=10%%): %.2fx\n", amdahls_law(0.10, max_threads));
}

int main(int argc, char *argv[]) {
 int max_threads = MAX_THREADS;

 // Allocate and initialize array
 double *arr = (double *)malloc(ARRAY_SIZE * sizeof(double));
 if (arr == NULL) {
 fprintf(stderr, "Memory allocation failed\n");
 return 1;
 }

 // Initialize with sequential values 1, 2, 3, ..., n
 // Sum should be n*(n+1)/2
 printf("Initializing array with %d elements...\n", ARRAY_SIZE);
 for (int i = 0; i < ARRAY_SIZE; i++) {
 arr[i] = (double)(i + 1);
 }

 double expected_sum = (double)ARRAY_SIZE * (ARRAY_SIZE + 1) / 2.0;
 printf("Expected sum: %.0f\n\n", expected_sum);

 // Storage for execution times
 double times[MAX_THREADS + 1];
 memset(times, 0, sizeof(times));

 // Measure sequential execution (baseline)
 printf("Running sequential reduction...\n");
 double start = get_time_seconds();
 double seq_result = sequential_sum(arr, ARRAY_SIZE);
 double seq_time = get_time_seconds() - start;
 times[1] = seq_time;

 printf("Sequential time: %.4f seconds\n", seq_time);
 printf("Sequential result: %.0f (verified: %s)\n\n", 
 seq_result, (seq_result == expected_sum) ? "YES" : "NO");

 // Measure parallel execution with different thread counts
 printf("Running parallel reductions (simulated with overhead)...\n");
 for (int p = 2; p <= max_threads; p++) {
 start = get_time_seconds();
 double par_result = simulated_parallel_sum(arr, ARRAY_SIZE, p);
 times[p] = get_time_seconds() - start;

 printf(" Threads: %2d, Time: %.4fs", p, times[p]);
 printf(" (Speedup: %.2fx, Efficiency: %.1f%%)\n",
 calculate_speedup(seq_time, times[p]),
 calculate_efficiency(calculate_speedup(seq_time, times[p]), p) * 100);
 }

 // Print comprehensive scaling analysis
 print_scaling_analysis(times, max_threads);

 // Demonstrate weak scaling concept
 printf("\n=========================================================\n");
 printf("WEAK SCALING CONCEPT DEMONSTRATION\n");
 printf("=========================================================\n");
 printf("In weak scaling, problem size increases with processors.\n");
 printf("Goal: Maintain constant execution time while solving larger problems.\n\n");

 printf("Example: If problem size doubles with 2x processors:\n");
 printf(" - Sequential time for size N: T(1)\n");
 printf(" - Parallel time for size 2N with 2 threads: T_p\n");
 printf(" - Weak speedup = (2 * T(1)) / T_p\n");
 printf(" - Ideal weak speedup with 2 threads = 2.0\n");

 // Cleanup
 free(arr);

 return 0;
}
